(window.webpackJsonp=window.webpackJsonp||[]).push([[23],{650:function(r,n){r.exports="\x3c!-- \r\ntitle: 02-C字符串\r\nsort: \r\n--\x3e \r\n# C字符串\r\n\r\n> C没有储存字符串的变量类型\r\n>\r\n> 可以使用char数组来储存\r\n>\r\n> 或者在开头`#define Str \"fzf404\"`\r\n\r\n\r\n## 获取字符\r\n\r\n- getchar()\r\n\r\n- putchar()\r\n\r\n  ```c\r\n  while ((ch = getchar()) != '\\n')\r\n  {\r\n      putchar(ch + 1);\r\n  }\r\n  ```\r\n\r\n## 字符串操作\r\n\r\n### `string.h`\r\n\r\n- `strlen()`\r\n\r\n- 输出字符串长度\r\n\r\n  > 不包括末尾的`\\0`\r\n  >\r\n  > `sizeof\"\"`包括\r\n\r\n\r\n### `ctype.h`\r\n\r\n- `isalpha()`\r\n\r\n  > 判断字符\r\n\r\n  ```c\r\n  while ((ch = getchar()) != '\\n')\r\n  {\r\n      if(isalpha(ch))\r\n      \tputchar(ch + 1);\r\n  }\r\n  ```\r\n\r\n  "}}]);